What does this program print when the user inputs `5`?

```cpp
#include <iostream>

int main() {
    int x;
    if (std::cin >> x)
        std::cout << "OK: " << x << '\n';
    else
        std::cout << "Fail\n";
    return 0;
}
```

What does this program print when input is `abc`? (Assume the program receives `abc\n` on stdin.)

```cpp
#include <iostream>
#include <limits>

int main() {
    int x = 42;
    if (!(std::cin >> x)) {
        std::cin.clear();
        std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');
        std::cout << "Bad\n";
    } else {
        std::cout << x << '\n';
    }
    return 0;
}
```
